import React, { useState, useEffect } from 'react';

const EventEdit = ({ eventId }) => {
  const [event, setEvent] = useState({
    event_id: eventId,
    event_name: '',
    event_state: ''
  });

  // イベントデータを取得する関数
  const fetchEventData = async () => {
    try {
      const response = await fetch(`/event/get?event_id=${eventId}`);
      if (!response.ok) {
        throw new Error('Network response was not ok');
      }
      const data = await response.json();
      setEvent({
        event_id: eventId,
        event_name: data.event_name,
        event_state: data.event_state
      });
    } catch (error) {
      console.error('イベントの取得に失敗しました。', error);
    }
  };

  // コンポーネントのマウント時にイベントデータを取得
  useEffect(() => {
    fetchEventData();
  }, [eventId]);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setEvent(prevState => ({
      ...prevState,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const response = await fetch('/event/edit', {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(event)
      });
      if (!response.ok) {
        throw new Error('Network response was not ok');
      }
      const updatedEvent = await response.json();
      console.log('イベントが更新されました。', updatedEvent);
      // 必要であれば、更新後の処理をここに記述
    } catch (error) {
      console.error('イベントの更新に失敗しました。', error);
    }
  };

  return (
    <div>
      <h2>イベント編集画面</h2>
      <form onSubmit={handleSubmit}>
        <div>
          <label>イベント名：</label>
          <input
            type="text"
            name="event_name"
            value={event.event_name}
            onChange={handleInputChange}
          />
        </div>
        <div>
          <label>イベント状態：</label>
          <select
            name="event_state"
            value={event.event_state}
            onChange={handleInputChange}
          >
            <option value="draft">下書き</option>
            <option value="open">公開中</option>
            <option value="close">終了</option>
          </select>
        </div>
        <button type="submit">更新</button>
      </form>
    </div>
  );
};

export default EventEdit;
